// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "./day9-scientificcalculator.sol";

contract Calculator {
    // basic math functions
    address public owner;
    address public scientificCalculatorAddress;

    constructor() {
        owner = msg.sender;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner can perform this action");
        _;
    }

    function add(uint256 a, uint256 b)public pure returns(uint256){
        uint256 result = a+b;
        return result;
    }

    function subtract(uint256 a, uint256 b)public pure returns(uint256){
        uint256 result = a-b;
        return result;
    }

    function multiply(uint256 a, uint256 b)public pure returns(uint256){
        uint256 result = a*b;
        return result;
    }

    function divide(uint256 a, uint256 b)public pure returns(uint256){
        require(b!= 0, "Cannot divide by zero");
        uint256 result = a/b;
        return result;
    }
    
    function setScientificCalculator(address _address) public onlyOwner {
        scientificCalculatorAddress = _address;
    }

    function calculatePower(uint256 base,  uint256 exponent) public view returns(uint256) {
        ScientificCalculator sc =  ScientificCalculator(scientificCalculatorAddress);
        uint256 result = sc.power(base, exponent);
        return result;
    }

    function calculateSquareRoot(uint256 number) public returns (uint256) {
        // 1. 检查数字不为负（虽然 uint 已经是正数了，但可以保留逻辑严谨性）
        require(number >= 0, "Cannot calculate square root of negative number");

        // 2. 打包：调用 squareRoot(uint256)，传入 number
        bytes memory data = abi.encodeWithSignature("squareRoot(uint256)", number);

        (bool success, bytes memory returnData) = scientificCalculatorAddress.call(data);
        require(success, "External call failed");

        uint256 result = abi.decode(returnData, (uint256));
        return result;
    }

    function calculateSquareRoot1(uint256 number) public returns (uint256) {
        require(number >= 0, "Cannot calculate square root of negative number");

        bytes memory data = abi.encodeWithSignature("squareRoot(uint256)", number);
        (bool success, bytes memory returnData) = scientificCalculatorAddress.call(data);
        require(success, "External call failed");

        uint256 result = abi.decode(returnData, (uint256));
        return result;
    }
}

// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract ScientificCalculator {
    // advanced functions will go here
    function power(uint256 base, uint256 exponent) public pure returns(uint256) {
        if (exponent == 0) return 1;
        else return (base ** exponent);
    }

    function squareRoot(uint256 number) public pure returns(uint256) {
        require(number >= 0, "Cannot calculate square root of negative number.");
        if (number == 0) return 0;

        uint256 result = number / 2;
        for (uint256 i = 0; i < 10; i++) {
            result = (result + number / result) / 2;
        }
        return result;
    }
}

